217	static ngx_int_t
218	ngx_http_xslt_header_filter(ngx_http_request_t *r)
219	{
220	    ngx_http_xslt_filter_ctx_t       *ctx;
221	    ngx_http_xslt_filter_loc_conf_t  *conf;
222	
223	    ngx_log_debug0(NGX_LOG_DEBUG_HTTP, r->connection->log, 0,
224	                   "xslt filter header");
225	
226	    if (r->headers_out.status == NGX_HTTP_NOT_MODIFIED) {
227	        return ngx_http_next_header_filter(r);
228	    }
229	
230	    conf = ngx_http_get_module_loc_conf(r, ngx_http_xslt_filter_module);
231	
232	    if (conf->sheets.nelts == 0
233	        || ngx_http_test_content_type(r, &conf->types) == NULL)
234	    {
235	        return ngx_http_next_header_filter(r);
236	    }
237	
238	    ctx = ngx_http_get_module_ctx(r, ngx_http_xslt_filter_module);
239	
240	    if (ctx) {
241	        return ngx_http_next_header_filter(r);
242	    }
243	
244	    ctx = ngx_pcalloc(r->pool, sizeof(ngx_http_xslt_filter_ctx_t));
245	    if (ctx == NULL) {
246	        return NGX_ERROR;
247	    }
248	
249	    ngx_http_set_ctx(r, ctx, ngx_http_xslt_filter_module);
250	
251	    r->main_filter_need_in_memory = 1;
252	    r->allow_ranges = 0;
253	
254	    return NGX_OK;
255	}
