258	static ngx_int_t
259	ngx_http_xslt_body_filter(ngx_http_request_t *r, ngx_chain_t *in)
260	{
261	    int                          wellFormed;
262	    ngx_chain_t                 *cl;
263	    ngx_http_xslt_filter_ctx_t  *ctx;
264	
265	    ngx_log_debug0(NGX_LOG_DEBUG_HTTP, r->connection->log, 0,
266	                   "xslt filter body");
267	
268	    if (in == NULL) {
269	        return ngx_http_next_body_filter(r, in);
270	    }
271	
272	    ctx = ngx_http_get_module_ctx(r, ngx_http_xslt_filter_module);
273	
274	    if (ctx == NULL || ctx->done) {
275	        return ngx_http_next_body_filter(r, in);
276	    }
277	
278	    for (cl = in; cl; cl = cl->next) {
279	
280	        if (ngx_http_xslt_add_chunk(r, ctx, cl->buf) != NGX_OK) {
281	
282	            if (ctx->ctxt->myDoc) {
283	
284	#if (NGX_HTTP_XSLT_REUSE_DTD)
285	                ctx->ctxt->myDoc->extSubset = NULL;
286	#endif
287	                xmlFreeDoc(ctx->ctxt->myDoc);
288	            }
289	
290	            xmlFreeParserCtxt(ctx->ctxt);
291	
292	            return ngx_http_xslt_send(r, ctx, NULL);
293	        }
294	
295	        if (cl->buf->last_buf || cl->buf->last_in_chain) {
296	
297	            ctx->doc = ctx->ctxt->myDoc;
298	
299	#if (NGX_HTTP_XSLT_REUSE_DTD)
300	            ctx->doc->extSubset = NULL;
301	#endif
302	
303	            wellFormed = ctx->ctxt->wellFormed;
304	
305	            xmlFreeParserCtxt(ctx->ctxt);
306	
307	            if (wellFormed) {
308	                return ngx_http_xslt_send(r, ctx,
309	                                       ngx_http_xslt_apply_stylesheet(r, ctx));
310	            }
311	
312	            xmlFreeDoc(ctx->doc);
313	
314	            ngx_log_error(NGX_LOG_ERR, r->connection->log, 0,
315	                          "not well formed XML document");
316	
317	            return ngx_http_xslt_send(r, ctx, NULL);
318	        }
319	    }
320	
321	    return NGX_OK;
322	}
