325	static ngx_int_t
326	ngx_http_xslt_send(ngx_http_request_t *r, ngx_http_xslt_filter_ctx_t *ctx,
327	    ngx_buf_t *b)
328	{
329	    ngx_int_t                         rc;
330	    ngx_chain_t                       out;
331	    ngx_pool_cleanup_t               *cln;
332	    ngx_http_xslt_filter_loc_conf_t  *conf;
333	
334	    ctx->done = 1;
335	
336	    if (b == NULL) {
337	        return ngx_http_filter_finalize_request(r, &ngx_http_xslt_filter_module,
338	                                               NGX_HTTP_INTERNAL_SERVER_ERROR);
339	    }
340	
341	    cln = ngx_pool_cleanup_add(r->pool, 0);
342	
343	    if (cln == NULL) {
344	        ngx_free(b->pos);
345	        return ngx_http_filter_finalize_request(r, &ngx_http_xslt_filter_module,
346	                                               NGX_HTTP_INTERNAL_SERVER_ERROR);
347	    }
348	
349	    if (r == r->main) {
350	        r->headers_out.content_length_n = b->last - b->pos;
351	
352	        if (r->headers_out.content_length) {
353	            r->headers_out.content_length->hash = 0;
354	            r->headers_out.content_length = NULL;
355	        }
356	
357	        conf = ngx_http_get_module_loc_conf(r, ngx_http_xslt_filter_module);
358	
359	        if (!conf->last_modified) {
360	            ngx_http_clear_last_modified(r);
361	            ngx_http_clear_etag(r);
362	
363	        } else {
364	            ngx_http_weak_etag(r);
365	        }
366	    }
367	
368	    rc = ngx_http_next_header_filter(r);
369	
370	    if (rc == NGX_ERROR || rc > NGX_OK || r->header_only) {
371	        ngx_free(b->pos);
372	        return rc;
373	    }
374	
375	    cln->handler = ngx_http_xslt_cleanup;
376	    cln->data = b->pos;
377	
378	    out.buf = b;
379	    out.next = NULL;
380	
381	    return ngx_http_next_body_filter(r, &out);
382	}
