385	static ngx_int_t
386	ngx_http_xslt_add_chunk(ngx_http_request_t *r, ngx_http_xslt_filter_ctx_t *ctx,
387	    ngx_buf_t *b)
388	{
389	    int               err;
390	    xmlParserCtxtPtr  ctxt;
391	
392	    if (ctx->ctxt == NULL) {
393	
394	        ctxt = xmlCreatePushParserCtxt(NULL, NULL, NULL, 0, NULL);
395	        if (ctxt == NULL) {
396	            ngx_log_error(NGX_LOG_ERR, r->connection->log, 0,
397	                          "xmlCreatePushParserCtxt() failed");
398	            return NGX_ERROR;
399	        }
400	        xmlCtxtUseOptions(ctxt, XML_PARSE_NOENT|XML_PARSE_DTDLOAD
401	                                |XML_PARSE_NONET|XML_PARSE_NOWARNING);
402	
403	        ctxt->sax->externalSubset = ngx_http_xslt_sax_external_subset;
404	        ctxt->sax->entityDecl = ngx_http_xslt_sax_entity_decl;
405	        ctxt->sax->setDocumentLocator = NULL;
406	        ctxt->sax->error = ngx_http_xslt_sax_error;
407	        ctxt->sax->fatalError = ngx_http_xslt_sax_error;
408	        ctxt->sax->_private = ctx;
409	
410	        ctx->ctxt = ctxt;
411	        ctx->request = r;
412	    }
413	
414	    err = xmlParseChunk(ctx->ctxt, (char *) b->pos, (int) (b->last - b->pos),
415	                        (b->last_buf) || (b->last_in_chain));
416	
417	    if (err == 0) {
418	        b->pos = b->last;
419	        return NGX_OK;
420	    }
421	
422	    ngx_log_error(NGX_LOG_ERR, r->connection->log, 0,
423	                  "xmlParseChunk() failed, error:%d", err);
424	
425	    return NGX_ERROR;
426	}
