429	static void
430	ngx_http_xslt_sax_external_subset(void *data, const xmlChar *name,
431	    const xmlChar *externalId, const xmlChar *systemId)
432	{
433	    xmlParserCtxtPtr ctxt = data;
434	
435	    xmlDocPtr                         doc;
436	    xmlDtdPtr                         dtd;
437	    ngx_http_request_t               *r;
438	    ngx_http_xslt_filter_ctx_t       *ctx;
439	    ngx_http_xslt_filter_loc_conf_t  *conf;
440	
441	    ctx = ctxt->sax->_private;
442	    r = ctx->request;
443	
444	    conf = ngx_http_get_module_loc_conf(r, ngx_http_xslt_filter_module);
445	
446	    ngx_log_debug3(NGX_LOG_DEBUG_HTTP, r->connection->log, 0,
447	                   "xslt filter extSubset: \"%s\" \"%s\" \"%s\"",
448	                   name ? name : (xmlChar *) "",
449	                   externalId ? externalId : (xmlChar *) "",
450	                   systemId ? systemId : (xmlChar *) "");
451	
452	    doc = ctxt->myDoc;
453	
454	#if (NGX_HTTP_XSLT_REUSE_DTD)
455	
456	    dtd = conf->dtd;
457	
458	#else
459	
460	    dtd = xmlCopyDtd(conf->dtd);
461	    if (dtd == NULL) {
462	        ngx_log_error(NGX_LOG_ERR, r->connection->log, 0,
463	                      "xmlCopyDtd() failed");
464	        return;
465	    }
466	
467	    if (doc->children == NULL) {
468	        xmlAddChild((xmlNodePtr) doc, (xmlNodePtr) dtd);
469	
470	    } else {
471	        xmlAddPrevSibling(doc->children, (xmlNodePtr) dtd);
472	    }
473	
474	#endif
475	
476	    doc->extSubset = dtd;
477	}
