480	static void
481	ngx_http_xslt_sax_entity_decl(void *data, const xmlChar *name, int type,
482	    const xmlChar *publicId, const xmlChar *systemId, xmlChar *content)
483	{
484	    xmlParserCtxtPtr ctxt = data;
485	
486	    ngx_http_request_t               *r;
487	    ngx_http_xslt_filter_ctx_t       *ctx;
488	    ngx_http_xslt_filter_loc_conf_t  *conf;
489	
490	    ctx = ctxt->sax->_private;
491	    r = ctx->request;
492	
493	    ngx_log_debug3(NGX_LOG_DEBUG_HTTP, r->connection->log, 0,
494	                   "xslt filter entityDecl: \"%s\" \"%s\" \"%s\"",
495	                   name ? name : (xmlChar *) "",
496	                   publicId ? publicId : (xmlChar *) "",
497	                   systemId ? systemId : (xmlChar *) "");
498	
499	    conf = ngx_http_get_module_loc_conf(r, ngx_http_xslt_filter_module);
500	
501	    if (systemId && !conf->external_entities) {
502	
503	        /*
504	         * If external entiries in the internal DTD subset are disabled,
505	         * we remove system identifiers from such entities.  This makes sure
506	         * that external entities cannot be used to directly request arbitrary
507	         * files, but still can be used with public identifiers, assuming these
508	         * are included into XML catalogs on the system.
509	         */
510	
511	        ngx_log_error(NGX_LOG_WARN, r->connection->log, 0,
512	                      "xslt filter external entity ignored: "
513	                      "\"%s\" \"%s\" \"%s\"",
514	                      name ? name : (xmlChar *) "",
515	                      publicId ? publicId : (xmlChar *) "",
516	                      systemId ? systemId : (xmlChar *) "");
517	
518	        if (publicId) {
519	            xmlSAX2EntityDecl(data, name, type, publicId, (xmlChar *) "",
520	                              content);
521	
522	        } else if (type == XML_EXTERNAL_GENERAL_PARSED_ENTITY) {
523	            xmlSAX2EntityDecl(data, name, XML_INTERNAL_GENERAL_ENTITY,
524	                              NULL, NULL, (xmlChar *) "");
525	
526	        } else if (type == XML_EXTERNAL_PARAMETER_ENTITY) {
527	            xmlSAX2EntityDecl(data, name, XML_INTERNAL_PARAMETER_ENTITY,
528	                              NULL, NULL, (xmlChar *) "");
529	        }
530	
531	        return;
532	    }
533	
534	    xmlSAX2EntityDecl(data, name, type, publicId, systemId, content);
535	}
