538	static void ngx_cdecl
539	ngx_http_xslt_sax_error(void *data, const char *msg, ...)
540	{
541	    xmlParserCtxtPtr ctxt = data;
542	
543	    int                          n;
544	    va_list                      args;
545	    ngx_http_xslt_filter_ctx_t  *ctx;
546	    u_char                       buf[NGX_MAX_ERROR_STR];
547	
548	    ctx = ctxt->sax->_private;
549	
550	    buf[0] = '\0';
551	
552	    va_start(args, msg);
553	    n = vsnprintf((char *) buf, NGX_MAX_ERROR_STR, msg, args);
554	    va_end(args);
555	
556	    if (n <= 0) {
557	        ngx_log_error(NGX_LOG_ERR, ctx->request->connection->log, ngx_errno,
558	                      "libxml2 error");
559	        return;
560	    }
561	
562	    if (n > NGX_MAX_ERROR_STR) {
563	        n = NGX_MAX_ERROR_STR;
564	    }
565	
566	    while (--n && (buf[n] == CR || buf[n] == LF)) { /* void */ }
567	
568	    ngx_log_error(NGX_LOG_ERR, ctx->request->connection->log, 0,
569	                  "libxml2 error: \"%*s\"", (size_t) (n + 1), buf);
570	}
