573	static ngx_buf_t *
574	ngx_http_xslt_apply_stylesheet(ngx_http_request_t *r,
575	    ngx_http_xslt_filter_ctx_t *ctx)
576	{
577	    int                               len, rc, doc_type;
578	    u_char                           *type, *encoding;
579	    ngx_buf_t                        *b;
580	    ngx_uint_t                        i;
581	    xmlChar                          *buf;
582	    xmlDocPtr                         doc, res;
583	    ngx_http_xslt_sheet_t            *sheet;
584	    ngx_http_xslt_filter_loc_conf_t  *conf;
585	
586	    conf = ngx_http_get_module_loc_conf(r, ngx_http_xslt_filter_module);
587	    sheet = conf->sheets.elts;
588	    doc = ctx->doc;
589	
590	    /* preallocate array for 4 params */
591	
592	    if (ngx_array_init(&ctx->params, r->pool, 4 * 2 + 1, sizeof(char *))
593	        != NGX_OK)
594	    {
595	        xmlFreeDoc(doc);
596	        return NULL;
597	    }
598	
599	    for (i = 0; i < conf->sheets.nelts; i++) {
600	
601	        ctx->transform = xsltNewTransformContext(sheet[i].stylesheet, doc);
602	        if (ctx->transform == NULL) {
603	            xmlFreeDoc(doc);
604	            return NULL;
605	        }
606	
607	        if (conf->params
608	            && ngx_http_xslt_params(r, ctx, conf->params, 0) != NGX_OK)
609	        {
610	            xsltFreeTransformContext(ctx->transform);
611	            xmlFreeDoc(doc);
612	            return NULL;
613	        }
614	
615	        if (ngx_http_xslt_params(r, ctx, &sheet[i].params, 1) != NGX_OK) {
616	            xsltFreeTransformContext(ctx->transform);
617	            xmlFreeDoc(doc);
618	            return NULL;
619	        }
620	
621	        res = xsltApplyStylesheetUser(sheet[i].stylesheet, doc,
622	                                      ctx->params.elts, NULL, NULL,
623	                                      ctx->transform);
624	
625	        xsltFreeTransformContext(ctx->transform);
626	        xmlFreeDoc(doc);
627	
628	        if (res == NULL) {
629	            ngx_log_error(NGX_LOG_ERR, r->connection->log, 0,
630	                          "xsltApplyStylesheet() failed");
631	            return NULL;
632	        }
633	
634	        doc = res;
635	
636	        /* reset array elements */
637	        ctx->params.nelts = 0;
638	    }
639	
640	    /* there must be at least one stylesheet */
641	
642	    if (r == r->main) {
643	        type = ngx_http_xslt_content_type(sheet[i - 1].stylesheet);
644	
645	    } else {
646	        type = NULL;
647	    }
648	
649	    encoding = ngx_http_xslt_encoding(sheet[i - 1].stylesheet);
650	    doc_type = doc->type;
651	
652	    ngx_log_debug3(NGX_LOG_DEBUG_HTTP, r->connection->log, 0,
653	                   "xslt filter type: %d t:%s e:%s",
654	                   doc_type, type ? type : (u_char *) "(null)",
655	                   encoding ? encoding : (u_char *) "(null)");
656	
657	    rc = xsltSaveResultToString(&buf, &len, doc, sheet[i - 1].stylesheet);
658	
659	    xmlFreeDoc(doc);
660	
661	    if (rc != 0) {
662	        ngx_log_error(NGX_LOG_ERR, r->connection->log, 0,
663	                      "xsltSaveResultToString() failed");
664	        return NULL;
665	    }
666	
667	    if (len == 0) {
668	        ngx_log_error(NGX_LOG_ERR, r->connection->log, 0,
669	                      "xsltSaveResultToString() returned zero-length result");
670	        return NULL;
671	    }
672	
673	    b = ngx_calloc_buf(r->pool);
674	    if (b == NULL) {
675	        ngx_free(buf);
676	        return NULL;
677	    }
678	
679	    b->pos = buf;
680	    b->last = buf + len;
681	    b->memory = 1;
682	
683	    if (encoding) {
684	        r->headers_out.charset.len = ngx_strlen(encoding);
685	        r->headers_out.charset.data = encoding;
686	    }
687	
688	    if (r != r->main) {
689	        return b;
690	    }
691	
692	    b->last_buf = 1;
693	
694	    if (type) {
695	        len = ngx_strlen(type);
696	
697	        r->headers_out.content_type_len = len;
698	        r->headers_out.content_type.len = len;
699	        r->headers_out.content_type.data = type;
700	
701	    } else if (doc_type == XML_HTML_DOCUMENT_NODE) {
702	
703	        r->headers_out.content_type_len = sizeof("text/html") - 1;
704	        ngx_str_set(&r->headers_out.content_type, "text/html");
705	    }
706	
707	    r->headers_out.content_type_lowcase = NULL;
708	
709	    return b;
710	}
