712	
713	static ngx_int_t
714	ngx_http_xslt_params(ngx_http_request_t *r, ngx_http_xslt_filter_ctx_t *ctx,
715	    ngx_array_t *params, ngx_uint_t final)
716	{
717	    u_char                 *p, *value, *dst, *src, **s;
718	    size_t                  len;
719	    ngx_uint_t              i;
720	    ngx_str_t               string;
721	    ngx_http_xslt_param_t  *param;
722	
723	    param = params->elts;
724	
725	    for (i = 0; i < params->nelts; i++) {
726	
727	        if (ngx_http_complex_value(r, &param[i].value, &string) != NGX_OK) {
728	            return NGX_ERROR;
729	        }
730	
731	        ngx_log_debug1(NGX_LOG_DEBUG_HTTP, r->connection->log, 0,
732	                       "xslt filter param: \"%s\"", string.data);
733	
734	        if (param[i].name) {
735	
736	            ngx_log_debug1(NGX_LOG_DEBUG_HTTP, r->connection->log, 0,
737	                           "xslt filter param name: \"%s\"", param[i].name);
738	
739	            if (param[i].quote) {
740	                if (xsltQuoteOneUserParam(ctx->transform, param[i].name,
741	                                          string.data)
742	                    != 0)
743	                {
744	                    ngx_log_error(NGX_LOG_ERR, r->connection->log, 0,
745	                                "xsltQuoteOneUserParam(\"%s\", \"%s\") failed",
746	                                param[i].name, string.data);
747	                    return NGX_ERROR;
748	                }
749	
750	                continue;
751	            }
752	
753	            s = ngx_array_push(&ctx->params);
754	            if (s == NULL) {
755	                return NGX_ERROR;
756	            }
757	
758	            *s = param[i].name;
759	
760	            s = ngx_array_push(&ctx->params);
761	            if (s == NULL) {
762	                return NGX_ERROR;
763	            }
764	
765	            *s = string.data;
766	
767	            continue;
768	        }
769	
770	        /*
771	         * parse param1=value1:param2=value2 syntax as used by parameters
772	         * specified in xslt_stylesheet directives
773	         */
774	
775	        if (param[i].value.lengths) {
776	            p = string.data;
777	
778	        } else {
779	            p = ngx_pnalloc(r->pool, string.len + 1);
780	            if (p == NULL) {
781	                return NGX_ERROR;
782	            }
783	
784	            ngx_memcpy(p, string.data, string.len + 1);
785	        }
786	
787	        while (p && *p) {
788	
789	            value = p;
790	            p = (u_char *) ngx_strchr(p, '=');
791	            if (p == NULL) {
792	                ngx_log_error(NGX_LOG_ERR, r->connection->log, 0,
793	                                "invalid libxslt parameter \"%s\"", value);
794	                return NGX_ERROR;
795	            }
796	            *p++ = '\0';
797	
798	            ngx_log_debug1(NGX_LOG_DEBUG_HTTP, r->connection->log, 0,
799	                           "xslt filter param name: \"%s\"", value);
800	
801	            s = ngx_array_push(&ctx->params);
802	            if (s == NULL) {
803	                return NGX_ERROR;
804	            }
805	
806	            *s = value;
807	
808	            value = p;
809	            p = (u_char *) ngx_strchr(p, ':');
810	
811	            if (p) {
812	                len = p - value;
813	                *p++ = '\0';
814	
815	            } else {
816	                len = ngx_strlen(value);
817	            }
818	
819	            ngx_log_debug1(NGX_LOG_DEBUG_HTTP, r->connection->log, 0,
820	                           "xslt filter param value: \"%s\"", value);
821	
822	            dst = value;
823	            src = value;
824	
825	            ngx_unescape_uri(&dst, &src, len, 0);
826	
827	            *dst = '\0';
828	
829	            ngx_log_debug1(NGX_LOG_DEBUG_HTTP, r->connection->log, 0,
830	                           "xslt filter param unescaped: \"%s\"", value);
831	
832	            s = ngx_array_push(&ctx->params);
833	            if (s == NULL) {
834	                return NGX_ERROR;
835	            }
836	
837	            *s = value;
838	        }
839	    }
840	
841	    if (final) {
842	        s = ngx_array_push(&ctx->params);
843	        if (s == NULL) {
844	            return NGX_ERROR;
845	        }
846	
847	        *s = NULL;
848	    }
849	
850	    return NGX_OK;
851	}
