905	static char *
906	ngx_http_xslt_entities(ngx_conf_t *cf, ngx_command_t *cmd, void *conf)
907	{
908	    ngx_http_xslt_filter_loc_conf_t *xlcf = conf;
909	
910	    ngx_str_t                         *value;
911	    ngx_uint_t                         i;
912	    ngx_pool_cleanup_t                *cln;
913	    ngx_http_xslt_file_t              *file;
914	    ngx_http_xslt_filter_main_conf_t  *xmcf;
915	
916	    if (xlcf->dtd) {
917	        return "is duplicate";
918	    }
919	
920	    value = cf->args->elts;
921	
922	    xmcf = ngx_http_conf_get_module_main_conf(cf, ngx_http_xslt_filter_module);
923	
924	    file = xmcf->dtd_files.elts;
925	    for (i = 0; i < xmcf->dtd_files.nelts; i++) {
926	        if (ngx_strcmp(file[i].name, value[1].data) == 0) {
927	            xlcf->dtd = file[i].data;
