929	        }
930	    }
931	
932	    cln = ngx_pool_cleanup_add(cf->pool, 0);
933	    if (cln == NULL) {
934	        return NGX_CONF_ERROR;
935	    }
936	
937	    xlcf->dtd = xmlParseDTD(NULL, (xmlChar *) value[1].data);
938	
939	    if (xlcf->dtd == NULL) {
940	        ngx_conf_log_error(NGX_LOG_ERR, cf, 0, "xmlParseDTD() failed");
941	        return NGX_CONF_ERROR;
942	    }
943	
944	    cln->handler = ngx_http_xslt_cleanup_dtd;
945	    cln->data = xlcf->dtd;
946	
947	    file = ngx_array_push(&xmcf->dtd_files);
948	    if (file == NULL) {
949	        return NGX_CONF_ERROR;
950	    }
951	
952	    file->name = value[1].data;
953	    file->data = xlcf->dtd;
954	
955	    return NGX_CONF_OK;
