960	static char *
961	ngx_http_xslt_stylesheet(ngx_conf_t *cf, ngx_command_t *cmd, void *conf)
962	{
963	    ngx_http_xslt_filter_loc_conf_t *xlcf = conf;
964	
965	    ngx_str_t                         *value;
966	    ngx_uint_t                         i, n;
967	    ngx_pool_cleanup_t                *cln;
968	    ngx_http_xslt_file_t              *file;
969	    ngx_http_xslt_sheet_t             *sheet;
970	    ngx_http_xslt_param_t             *param;
971	    ngx_http_compile_complex_value_t   ccv;
972	    ngx_http_xslt_filter_main_conf_t  *xmcf;
973	
974	    value = cf->args->elts;
975	
976	    if (xlcf->sheets.elts == NULL) {
977	        if (ngx_array_init(&xlcf->sheets, cf->pool, 1,
978	                           sizeof(ngx_http_xslt_sheet_t))
979	            != NGX_OK)
980	        {
981	            return NGX_CONF_ERROR;
982	        }
983	    }
984	
985	    sheet = ngx_array_push(&xlcf->sheets);
986	    if (sheet == NULL) {
987	        return NGX_CONF_ERROR;
988	    }
989	
990	    ngx_memzero(sheet, sizeof(ngx_http_xslt_sheet_t));
991	
992	    if (ngx_conf_full_name(cf->cycle, &value[1], 0) != NGX_OK) {
993	        return NGX_CONF_ERROR;
994	    }
995	
996	    xmcf = ngx_http_conf_get_module_main_conf(cf, ngx_http_xslt_filter_module);
997	
998	    file = xmcf->sheet_files.elts;
999	    for (i = 0; i < xmcf->sheet_files.nelts; i++) {
1000	        if (ngx_strcmp(file[i].name, value[1].data) == 0) {
1001	            sheet->stylesheet = file[i].data;
1002	            goto found;
1003	        }
1004	    }
1005	
1006	    cln = ngx_pool_cleanup_add(cf->pool, 0);
1007	    if (cln == NULL) {
1008	        return NGX_CONF_ERROR;
1009	    }
1010	
1011	    sheet->stylesheet = xsltParseStylesheetFile(value[1].data);
1012	    if (sheet->stylesheet == NULL) {
1013	        ngx_conf_log_error(NGX_LOG_ERR, cf, 0,
1014	                           "xsltParseStylesheetFile(\"%s\") failed",
1015	                           value[1].data);
1016	        return NGX_CONF_ERROR;
1017	    }
1018	
1019	    cln->handler = ngx_http_xslt_cleanup_stylesheet;
1020	    cln->data = sheet->stylesheet;
1021	
1022	    file = ngx_array_push(&xmcf->sheet_files);
1023	    if (file == NULL) {
1024	        return NGX_CONF_ERROR;
1025	    }
1026	
1027	    file->name = value[1].data;
1028	    file->data = sheet->stylesheet;
1029	
1030	found:
1031	
1032	    n = cf->args->nelts;
1033	
1034	    if (n == 2) {
1035	        return NGX_CONF_OK;
1036	    }
1037	
1038	    if (ngx_array_init(&sheet->params, cf->pool, n - 2,
1039	                       sizeof(ngx_http_xslt_param_t))
1040	        != NGX_OK)
1041	    {
1042	        return NGX_CONF_ERROR;
1043	    }
1044	
1045	    for (i = 2; i < n; i++) {
1046	
1047	        param = ngx_array_push(&sheet->params);
1048	        if (param == NULL) {
1049	            return NGX_CONF_ERROR;
1050	        }
1051	
1052	        ngx_memzero(param, sizeof(ngx_http_xslt_param_t));
1053	        ngx_memzero(&ccv, sizeof(ngx_http_compile_complex_value_t));
1054	
1055	        ccv.cf = cf;
1056	        ccv.value = &value[i];
1057	        ccv.complex_value = &param->value;
1058	        ccv.zero = 1;
1059	
1060	        if (ngx_http_compile_complex_value(&ccv) != NGX_OK) {
1061	            return NGX_CONF_ERROR;
1062	        }
1063	    }
1064	
1065	    return NGX_CONF_OK;
1066	}
