1181	ngx_http_xslt_filter_merge_conf(ngx_conf_t *cf, void *parent, void *child)
1182	{
1183	    ngx_http_xslt_filter_loc_conf_t *prev = parent;
1184	    ngx_http_xslt_filter_loc_conf_t *conf = child;
1185	
1186	    if (conf->dtd == NULL) {
1187	        conf->dtd = prev->dtd;
1188	    }
1189	
1190	    if (conf->sheets.nelts == 0) {
1191	        conf->sheets = prev->sheets;
1192	    }
1193	
1194	    if (conf->params == NULL) {
1195	        conf->params = prev->params;
1196	    }
1197	
1198	    if (ngx_http_merge_types(cf, &conf->types_keys, &conf->types,
1199	                             &prev->types_keys, &prev->types,
1200	                             ngx_http_xslt_default_types)
1201	        != NGX_CONF_OK)
1202	    {
1203	        return NGX_CONF_ERROR;
1204	    }
1205	
1206	    ngx_conf_merge_value(conf->last_modified, prev->last_modified, 0);
1207	    ngx_conf_merge_value(conf->external_entities, prev->external_entities, 0);
1208	
1209	    return NGX_CONF_OK;
